const { execSync } = require('child_process');

let success = true;
let output = '';
let error = '';

try {
  output = execSync(
    'cmd /c C:\\Users\\???\\Desktop\\run-docker.bat',
    { encoding: 'utf8' }
  );
} catch (err) {
  success = false;
  error = err.message;
  output = err.stdout || '';
}

return [{
  json: {
    success,
    output,
    error,
    timestamp: new Date().toISOString()
  }
}];

