parameters.jsCode:
const fs = require('fs');

const path = 'C:\\Users\\???\\Desktop\\mercado_logs.csv';

const now = new Date().toISOString();

const success = $json.success;

const rawText = ($json.output || $json.error || '');

const output = String(rawText)
  .replace(/\n/g, ' ')
  .replace(/,/g, ';')
  .replace(/"/g, "'")
  .slice(0, 2000);

const statusText = success ? 'OK' : 'ERROR';

const line = `${now},${statusText},"${output}"\n`;

let saved = true;
let error = '';

try {
  fs.appendFileSync(path, line);
} catch (err) {
  saved = false;
  error = err.message;
}

return [{
  json: {
    success,
    saved,
    line,
    error
  }
}];

const output = $json.output;

const match = output.match(/=== PIPELINE_RESULT ===\s*([\s\S]*)/);

let result = null;

if (match) {
  try {
    result = JSON.parse(match[1]);
  } catch (e) {
    result = null;
  }
}

return [{
  json: {
    ...$json,
    result
  }
}];
